var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 샤레이드\\n<color=#ffd34c>제 6 난민지구</color>","JPN":"管理局直轄都市シャレード\\n<color=#ffd34c>第6難民地区</color>","ENG":"Administration Direct Control City, Charade.\\n<color=#ffd34c>6th Refugee District.</color>","TWN":"管理局直轄城市查雷德。\\n <color=#ffd34c>第6難民區。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"좋은 말 할 때 내놔. 왜 귀찮게 엉겨 붙고 그래?","JPN":"いつまでもまとわり付いてないで、優しくしてやってるうちに寄こしといた方がいいぞ？","ENG":"Hand it over while I'm being nice. Why make things harder for yourself?","TWN":"趁著我還能好好說話，快交出來。幹嘛這麼煩人地糾纏不休？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"싫어! 이건 동생들 약값이란 말이야!!","JPN":"いや！　これはみんなの薬代なの！！","ENG":"No! This is for my sisters' medicine!","TWN":"不行！這是給弟弟妹妹們買藥的錢！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"아이고~. 이렇게 맞으면 네 약값만 더 들어요. 괜히 고집부리지 말고 힘 빼, 응?","JPN":"おいおい、殴られりゃおまえの分の薬代が増えるんだぜ？　意地張らねぇで手を放せ。な？","ENG":"Aww, sweet. Keep this up and you'll just rack up more medical bills. Don't be stubborn and give it here!","TWN":"哎喲～這樣打下去只會讓你的藥費增加。別固執了，鬆手，好嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_FOOT_STEP"},{"id":"L9_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"끄으…! 이거 놔, 놓으란 말이야!!","JPN":"くう……！　いやだ、絶対放さない！！","ENG":"Ugh...! Let go of me, I said let go!","TWN":"呃……！放開，叫你放開！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"당신들! 거기서 뭐하는 거야?","JPN":"あんたたち！　そこで何をしているの？","ENG":"Hey, you two! What do you think you're doing?","TWN":"你們！在那裡幹什麼呢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"엠마, 괜찮아? 어디 다친 덴 없어?","JPN":"エマ、大丈夫？　どこか怪我してない？","ENG":"Emma, are you okay? Did they hurt you?","TWN":"艾瑪，你沒事吧？有沒有受傷？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"레, 레이첼 언니이이이-!","JPN":"れ、レイチェルお姉ちゃーん！","ENG":"R-Rachel!","TWN":"瑞，瑞秋姊姊——！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"지금 이게 뭐하는 짓이에요? 다 큰 어른이 애들 상대로 부끄럽지도 않아요?","JPN":"いったい何なんですか？　大人が子供相手に、恥ずかしくないんですか？","ENG":"What do you think you're doing? Grown men picking on a kid. Aren't you ashamed?","TWN":"現在這是在幹什麼？都是成年人了，對孩子這樣不覺得羞愧嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"그야 부끄럽지. 다 큰 어른이 애 돈 하나 못 뜯고 있는데.","JPN":"そりゃあ恥ずかしいさ。いい大人がガキから金も取れずにいるなんてな。","ENG":"Sure, I'm ashamed—ashamed that I can't even squeeze some pocket change out of a brat.","TWN":"當然會覺得丟臉。都已經是成年人了，卻連小孩的錢都拿不到。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐하고 있어? 빨리 이 녀석 안 치워?!","JPN":"なにしてんだ！　さっさとこのガキどかせ！","ENG":"What are you waiting for? Get this little pest outta my way!","TWN":"你幹什麼呢？還不趕緊解決掉這個傢伙？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"형님. 저 꼬마. 호라이즌이 대표로 있는 사채업장에서 일하는 애입니다.","JPN":"兄貴。このガキ、ホライズンが代表をやってる闇金事務所で働いてるやつです。","ENG":"Sir, that kid works for the loan shark Horizon.","TWN":"大哥。那個小孩是在地平線擔任代表的高利貸公司工作的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"응? 국제적으로 폭행 범죄를 일으킨 그 미치광이?","JPN":"あ？　あの国際的に暴行事件を起こした狂人のところか？","ENG":"Huh? That psycho who committed assault on an international scale?","TWN":"嗯？那個國際上製造暴力犯罪的瘋子？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"양아치들도 호라이즌 무서운 줄은 아나 보네. 그리고 사채업장이 아니라 투자기금이거든?","JPN":"チンピラでもホライズンは怖いのね。あと、闇金じゃなくてファンドって言ってくれる？","ENG":"So even thugs know to fear Horizon, huh? And we're not loan shark, we're an investment fund, thank you.","TWN":"連混混們都知道要怕地平線了啊。而且這不是高利貸公司，而是投資基金喔？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"무서운 꼴 보기 싫으면 빨리 줄행랑이나 치셔!","JPN":"痛い目見たくなかったら、さっさと逃げることね！","ENG":"If you don't wanna see something scary, I suggest you run while you can.","TWN":"不想看到可怕的場面就趕快逃跑吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"흐음… 그래, 그렇단 말이지?","JPN":"ふむ……なるほど、そういうことか？","ENG":"Hmm... Is that so?","TWN":"嗯…好吧，是這樣嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"잘됐네. 저년 인질로 잡으면 한몫 두둑이 챙길 수 있겠다, 야.","JPN":"ちょうどいい。あの女を人質に取れば一儲けできるんじゃねぇか？","ENG":"Well, even better. If we grab her as a hostage, we can cash in big time.","TWN":"太好了。抓住那個女人當人質的話，可以大賺一筆，嘿嘿。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐?","JPN":"な、何？","ENG":"W-what?!","TWN":"什，什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"괜찮을까요? 들리는 소문으로는 관리국이랑 연줄이 있다는데.","JPN":"いいんですか？　噂だと管理局につてがあるらしいですけど。","ENG":"You sure that's a good idea? Rumor is she's got ties to the Administration.","TWN":"沒問題嗎？聽說她們和管理局有關係。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"넌 소문을 믿냐? 그냥 우리 같은 놈들 휘어잡으려고 적당히 흘리는 거야.","JPN":"でたらめだろ、そんな噂。俺たちみてぇなやつらを脅すために適当な話流してるに決まってる。","ENG":"You believe every rumor you hear? That's just smoke they blow to keep guys like us in line.","TWN":"你相信傳聞嗎？那只是為了控制我們這樣的人而故意散佈的消息罷了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"관리국이랑 연줄 있는 녀석이 뭐가 아쉬워서 난민지구에 투자기금을 차려?","JPN":"管理局につてがあるやつが難民地区でファンドなんか出すか。","ENG":"Someone with real connections to the Administration wouldn't be running some investment fund in the refugee district.","TWN":"和管理局有關係的人為什麼要在難民區設立投資基金？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 아저씨들 후회한다? 나 호라이즌 말고도 무서운 사람 많이 알거든?","JPN":"お、おじさんたち、後悔するよ？　アタシ、ホライズンの他にも怖い知り合いたくさんいるんだからね。","ENG":"Y-you guys are gonna regret this! I know plenty of scary people besides Horizon!","TWN":"啊，叔叔們後悔了嗎？我除了地平線之外，還認識很多可怕的人喔？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"총사대장님이랑, 중사님이랑, 해, 해적 언니랑, 그리고 또……!","JPN":"銃士隊長とか、軍曹とか、か、海賊のお姉ちゃんとか。あと……！","ENG":"Like General Musketeer, Sergeant! And a scary pirate lady! And, uh...!","TWN":"總隊長，中士，海，海盜姊姊，還有……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"예예. 네 눈 앞에 있는 아저씨도 무서운 사람이에요.","JPN":"へいへい、お前の目の前にいるおじさんも怖い人なんだぜ。","ENG":"Yeah, yeah. And I'm a scary man standing right in front of you.","TWN":"是是。你面前的這個叔叔也是個可怕的人喔。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이거 놔! 누구, 누구 없어요?","JPN":"放してよ！　誰か、誰かいませんか？","ENG":"Let go of me! Is anyone there?! Someone help!","TWN":"放開我！有沒有人啊？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"뭐야, 구경 났어? 넌 뭔데…… ","JPN":"なに見てやがる？　お前なに……","ENG":"Huh? Who the hell are you–","TWN":"什麼啊，來看熱鬧的嗎？你是什麼人……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"자세히 보니 꽤 반반하네? 차림도 허름한데 그런 쪽에서 일하는 거야?","JPN":"よく見たらかわいい顔してるな。身なりもボロボロだし、もしかしてそっち系で働いてんの？","ENG":"Now that I look, you're pretty cute. Clothes are kinda shabby though... You working in the streets?","TWN":"仔細一看還挺不錯的嘛？穿得這麼樸素，是在那種地方工作嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"잘 됐네! 마침 일이 끝나기 직전이었거든. 여기서 조금만 기다리면…….","JPN":"ちょうどいい。もうすぐ仕事終わるから、ちょっと待ってく……","ENG":"Perfect timing. We were just about to wrap up here. Just hang tight, and...","TWN":"太好了！正好快要結束工作了。在這裡稍等一下……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"비켜.","JPN":"どけ。","ENG":"Move.","TWN":"讓開！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"응? 뭐라고?","JPN":"あ？　何だと？","ENG":"Huh? What did you say?","TWN":"嗯？你說什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"끄아아아아악!!","JPN":"くあああああっ！！","ENG":"Aaargh!","TWN":"啊啊啊啊啊！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"뭐, 뭐야. 이년이 미쳤나!","JPN":"な、何しやがるてめぇー！","ENG":"W-what's wrong with you, you psycho?!","TWN":"什，什麼？這女人瘋了嗎！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"으아아악-! 내 손, 내 손이……!!","JPN":"ぐわああっ！　手が、俺の手が……！！","ENG":"AAARGH! MY HAND! MY HAND...!!","TWN":"啊啊啊！我的手，我的手……！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"역시 날이 무뎌졌나. 생각처럼 깔끔하게 베이진 않는군.","JPN":"やはり刃がなまってしまったか。思うようにきれいに斬れないな。","ENG":"Guess my blade's dulled. Didn't cut as clean as I hoped.","TWN":"果然刀刃變鈍了嗎？不像想像中那樣乾淨俐落地切開啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"너어…! 실수하는 거야. 우리가 누군 줄 알아?!","JPN":"お前……！　後悔するぞ。俺たちが誰だかわかってんのか！？","ENG":"Hey...! You'll regret this! Do you have any idea who we are?!","TWN":"你這傢伙…！竟敢犯錯。你知道我們是誰嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"관심 없다. 비켜.","JPN":"興味ない。どけ。","ENG":"Don't care. Move.","TWN":"沒興趣。讓開。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_B","text":{"KOREA":"혀, 형님. 상처가 심하세요. 일단 치료부터 해야…….","JPN":"あ、兄貴。怪我がやばいです。とりあえず手当を……","ENG":"S-sir, that's a bad wound. We need to get you patched up first–","TWN":"大哥，你傷得很重。先得治療……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BULLY_PRIDE_NPC_A","text":{"KOREA":"크으윽…! 두고 보자, 네 얼굴 기억했다!!","JPN":"くううっ……！　覚えてろよ。お前の顔、忘れねえからな！！","ENG":"Grr...! This isn't over! I'll remember you!!","TWN":"咳呃呃……！等著瞧，我記住你的臉了！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BULLY_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BULLY_PRIDE_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"꼴 좋다! 상처 곪아서 평생 병원 신세나 지셔!","JPN":"ざまあ見ろ！　傷が悪化して一生入院しちまえ！","ENG":"Serves you right! Hope that festers and you rot in a hospital bed forever!","TWN":"活該！傷口化膿就一輩子待在醫院吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"펴, 평생은 그렇고 한 일 년 신세 져라, 이 나쁜 놈들아!!","JPN":"い、一生はちょっと言い過ぎだから、1年ぐらい入院しちゃえ、ごろつきども！！","ENG":"F-forever's a bit much. A year in the hospital should do it, you jerks!","TWN":"哼，雖然不是一輩子，但至少給我待上一年吧，你們這些壞蛋！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"감사합니다. 언니가 아니었으면 큰일 날 뻔했어요.","JPN":"ありがとうございます。おかげで助かりました。","ENG":"Thank you. If it weren't for you, we'd have been in real trouble.","TWN":"謝謝你！要不是姊姊，我們就真的要完蛋了！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"자, 자. 엠마도 얼른 배꼽 인사해야지?","JPN":"ほら、エマも。深くお辞儀して。","ENG":"Come on, Emma. Say thank you properly.","TWN":"來，來。艾瑪也快點鞠躬道謝吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"으, 응?","JPN":"う、うん？","ENG":"H-hmm?","TWN":"嗯，嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"아… 가, 감사합니다!","JPN":"あ……あ、ありがとうございます！","ENG":"Ah... Th-thank you!","TWN":"啊……感，感謝！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……별로, 도와준 건 아니야.","JPN":"……別に、助けたわけではない。","ENG":"...I didn't do it to help.","TWN":"……其實，我並沒有幫上什麼忙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그것보다 근방에 실력 좋은 수리공이 있다던데.","JPN":"それより、この辺に腕利きの修理工がいると聞いたが。","ENG":"Anyway, I heard there's a skilled mechanic around here.","TWN":"比起這個，聽說附近有個技術很好的修理工。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"수리공? 아, 햄스워스 아저씨를 찾아오셨구나?","JPN":"修理工？　ああ、ヘムズワースさんを探しているんですね？","ENG":"A mechanic? Oh! You're looking for Mr. Helmsworth, right?","TWN":"修理工？喔，你是來找漢姆沃斯先生的吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아저씨가 머무는 곳은 이 길을 쭉 따라가면 나와요. 뭣하면 제가 안내해드릴까요?","JPN":"この道をまっすぐ行くと、おじさんのとこに行けますよ。なんならアタシが案内しましょうか？","ENG":"Just follow this road and you'll find where he's staying. I can show you the way if you want?","TWN":"叔叔住的地方沿著這條路一直走就到了。要不我帶你去吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"충분해. 시간이 없으니 이만 가보지.","JPN":"十分だ。急いでいるので、私はこれで失礼する。","ENG":"That's enough. I don't have time. I'll be going now.","TWN":"不用客氣。沒時間了，我得走了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 그치만 사례라도…….","JPN":"あ、でもお礼を……","ENG":"Wait, at least let us thank you proper–","TWN":"啊，但是至少也要表示一下感謝……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"……하고 싶은데, 이름도 안 알려주고 떠나시네.","JPN":"……したいのに、名前も教えてくれなかったね。","ENG":"...Or not. She left without even telling us her name.","TWN":"……想告訴你，但你連名字都沒說就離開了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"왜 그래? 엠마?","JPN":"どうしたの、エマ？","ENG":"What is it, Emma?","TWN":"怎麼了？艾瑪？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"응? 아무것도 아니야.","JPN":"ん？　なんでもない。","ENG":"Huh? Nothing.","TWN":"嗯？沒什麼。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"EMMA_PRIDE_NULL_NULL","text":{"KOREA":"그냥…… 저 분이 내가 동경하는 기사님을 닮은 것 같아서.","JPN":"ちょっと……憧れの騎士様に似ている気がして。","ENG":"It's just... she kind of looked like the knight I admire.","TWN":"只是……那位好像和我仰慕的騎士很相似。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMMA_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"흐음. 무기는 전문분야가 아니긴 해도 이렇게 망가진 검은 또 간만에 보는구만.","JPN":"ふむ。武器は専門ではないが、こんなに壊れた剣は久しぶりに見るな。","ENG":"Hmm. I'm no expert in weapons, but it's been a while since I've seen a sword this busted.","TWN":"嗯。雖然武器不是我的專業領域，但這種損壞的劍也是很久沒見過了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이정도면 새 검을 쓰는 게 낫지 않나?","JPN":"さすがに新調したほうがよくないか？","ENG":"Wouldn't it be faster to just get a new one?","TWN":"這樣的話，還是用新劍比較好吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무기를 바꾸면 적응하는데 시간이 걸리더군. 별로 선호하는 방식은 아니야.","JPN":"武器を変えると慣れるまで時間がかかる。できればしたくない。","ENG":"Adapting to a new weapon slows me down. Not really my thing.","TWN":"換武器需要時間適應。我不太喜歡這種方式。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"명인이라 들었는데 수리는 힘든 건가?","JPN":"名人だと聞いたが、修理は難しいのか？","ENG":"They say you're a master craftsman. Is the repair too difficult?","TWN":"聽說你是大師，修理很難嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"명인은 무슨. 여기 머무는 김에 이것저것 수리했더니 별 소문이 다 퍼졌구만.","JPN":"名人？　ここに留まるついでにあれこれ修理してやったら、変な噂が広まってしまったな。","ENG":"Master craftsman, my foot. I just fixed a few things while staying here, and now I'm a legend, apparently.","TWN":"什麼大師啊。趁著在這裡待著，修了些東西，結果各種傳聞都傳開了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"힘들긴 해도 불가능한 건 아니야.","JPN":"難しいが、不可能ではない。","ENG":"It's tough, but not impossible.","TWN":"雖然辛苦，但並不是不可能。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"날을 손 봐줄 테니 잠시 기다리게.","JPN":"刃を少し手入れしてやるから、しばらく待っとれ。","ENG":"I'll take care of the blade. Give me a moment.","TWN":"我來修理一下刀，大家稍等一下。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"생각보다 장비가 소박하군.","JPN":"思っていたより素朴な設備だな。","ENG":"Your setup's simpler than I expected.","TWN":"設備比想像中要簡陋呀。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"겸사겸사 하는 일이라고 말했잖나. 원래 공방은 그라운드원에 있다고.","JPN":"ついでにやっていると言っただろう。もともと工房はグラウンド・ワンにある。","ENG":"Told you, this is a side gig. My real workshop's in Ground One.","TWN":"我不是說過這是順便做的事情嗎？原本工坊是在G1的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그래도 난민지구에서 이 정도면 꽤 훌륭하지. 덕분에 이런저런 이야기도 많이 듣고.","JPN":"だが、難民地区でこれだけあれば立派な方だ。おかげで色んな話も聞ける。","ENG":"Still, this is pretty good for a place in the refugee district. I've picked up all kinds of stories here.","TWN":"即便是在難民區，這樣的情況也算相當不錯了。多虧如此，我也聽到了很多各種各樣的故事。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"최근 언더그라운드의 정보상 위주로 들쑤시고 다니는 여자, 자네 맞지?","JPN":"最近アンダーグラウンドの情報屋を探し回っている女がいるって話だが、お前さんだろう？","ENG":"You're the one poking around intel dealers in the Underground lately, right?","TWN":"最近在地下世界到處搜集情報的女人，是你吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그렇다면, 관리국에 신고라도 할 건가?","JPN":"そうだと言えば、管理局に通報するか？","ENG":"And if I am? Are you going to report me to the Administration?","TWN":"那麼，你會向管理局舉報嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"할 거면 조용하게 했지. 내가 미쳤다고 자네 앞에서 떠벌리겠나?","JPN":"通報する気ならこっそりやっとる。本人の前で言うやつがあるか？","ENG":"If I was, I wouldn't be saying it out loud in front of you. I'm not that stupid.","TWN":"要做就悄悄地做。我又不是瘋了，怎麼會在你面前大肆宣揚呢？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그냥 노파심에 하는 얘기야. 자네 같은 용병들은 얼마 안 가 부고 소식만 전했거든.","JPN":"まあ、年寄りの余計なお節介だ。お前さんみたいな傭兵は、そう長くもたずに訃報だけが届くもんでな。","ENG":"Just speaking out of concern. Mercs like you tend to wind up on a death notice before long.","TWN":"只是出於關心才說的。像你這樣的傭兵沒過多久就只剩下訃告了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"애들을 도와준 걸 보면 나쁜 사람은 아닌 것 같은데, 너무 무리하진 말게.","JPN":"子どもたちを助けたのを見りゃ、悪い奴じゃなさそうだがな。あんまり無理はするんじゃないぞ。","ENG":"But since you helped the kids, I doubt you're a bad person. Just don't push yourself too far.","TWN":"看你幫助了孩子們，感覺你不是壞人，但不要太勉強自己喔。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"다 됐네. 그리고 슬슬 본론을 꺼내 줬으면 싶군.","JPN":"さて、完成だ。そろそろ本題を切り出してくれないか。","ENG":"All done. Now then, I'd appreciate it if you got to the real reason you came.","TWN":"都好了。希望你能慢慢說出正題。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"설마 이런 난민지구에 검 하나 고치자고 찾아온 건 아니겠지?","JPN":"まさか剣1本直すために、こんな難民地区まで足を運んだわけではあるまい。","ENG":"Surely you didn't come all the way to the refugee district just to fix a sword?","TWN":"難道你是為了修一把劍才來到這個難民區的嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"눈치가 빠르군.","JPN":"察しがいいな。","ENG":"You're sharp.","TWN":"你還真是會察言觀色。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"눈칫밥도 경력이야. 사람들이 괜히 경력직, 경력직 하겠는가?","JPN":"察しがいいのも長年の経験があってこそだ。だから皆経験豊富な人材を求めるんじゃないか。","ENG":"Being nosy's part of the job. There's a reason experience matters, y'know?","TWN":"察言觀色也是一種經驗。人們為什麼總是說有經驗的職員呢？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"최근 눈에 밟히던 불량배들도 혼내줬으니, 내 힘이 닿는 선에서는 뭐든 도와주겠네.","JPN":"最近気になっていたごろつきどもを懲らしめてくれた礼も兼ねて、ワシにできることならなんでも手伝おう。","ENG":"And since you beat up those thugs I had my eye on, I'll help you however I can.","TWN":"最近那些惹眼的混混也被我教訓了，在我能力範圍內，我會盡力幫助你。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……당신이 정비사를 맡고 있는 카나리아 스쿼드.","JPN":"……あなたが整備士を務めているカナリア・スクワッド。","ENG":"...You're the mechanic for Canary Squad.","TWN":"……你是金絲雀小隊的機械師。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 팀의 코치를 만나고 싶다.","JPN":"そのチームのコーチに会いたい。","ENG":"I want to meet the team's coach.","TWN":"我想見那個隊的教練。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"자, 자네 설마 내 고용주를 처리하러 온 건가?","JPN":"お、お前さん、まさかワシの雇い主を始末しに来たのか？","ENG":"Whoa, don't tell me you're here to take out my boss?","TWN":"喂，你該不會是來對付我的雇主吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어쩐지 주변에 여자밖에 없더라니! 내 진작 인간관계가 파국으로 치닫을 줄 알았네!!","JPN":"周りに女しかいない人間なんだ！　いつかは関係が破綻すると思っとった！","ENG":"No wonder he's always surrounded by women! I knew this whole thing would go off the rails eventually!!","TWN":"難怪周圍都是女人！我早就知道人際關係會走向破裂！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……이야기를 나누고 싶을 뿐이야.","JPN":"……少し話したいだけだ。","ENG":"...I just want to talk.","TWN":"……我只是想聊聊而已。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"뭐야. 그런 거였으면 진작 말하지 그랬나.","JPN":"なんだ。そういうことなら最初からそう言ってくれ。","ENG":"Pfft, well why didn't you say so in the first place?","TWN":"什麼啊，既然是那樣的事情，那你怎麼不早說呢。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그 양반이라면 건틀렛 경기장으로 가면 만날 수 있네. 안 그래도 오늘이 경기 날이거든.","JPN":"その男ならガントレットの競技場に行けば会える。ちょうど今日試合があるんでな。","ENG":"You'll find him at the Gauntlet Arena. They have a match today anyway.","TWN":"如果是那位的話，可以去聖鎧競技場見到他。今天正好是比賽日。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"상대가… 그래.","JPN":"相手が……そうだな。","ENG":"Their opponent was... Right.","TWN":"對方……嗯。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"분명 <color=#ffd34c>조디악 나이츠</color>라는 태스크포스였지.","JPN":"確か、<color=#ffd34c>ゾディアックナイツ</color>というタスクフォースだった。","ENG":"It's that TASKFORCE called the <color=#ffd34c>Zodiac Knights</color>.","TWN":"肯定是<color=#ffd34c>十二宮騎士</color>的特遣勢力吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};